import { motion } from 'framer-motion';
import { useAuthStore } from '@store/authStore';

export function Dashboard() {
  const { user } = useAuthStore();

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      className="space-y-6"
    >
      {/* Header */}
      <div>
        <h1 className="text-3xl font-bold text-foreground">Dashboard</h1>
        <p className="text-muted-foreground mt-2">
          Welcome to MaxHub, {user?.firstName}!
        </p>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {[
          { label: 'Active Projects', value: '12', color: 'bg-blue-500' },
          { label: 'Pending Tasks', value: '28', color: 'bg-yellow-500' },
          { label: 'Team Members', value: '24', color: 'bg-green-500' },
          { label: 'Pending Approvals', value: '5', color: 'bg-red-500' },
        ].map((stat) => (
          <motion.div
            key={stat.label}
            initial={{ y: 20, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            className="bg-card rounded-lg p-6 border border-border"
          >
            <div className={`w-12 h-12 rounded-lg ${stat.color}/20 flex items-center justify-center mb-4`}>
              <div className={`w-2 h-2 rounded-full ${stat.color}`} />
            </div>
            <p className="text-muted-foreground text-sm">{stat.label}</p>
            <p className="text-3xl font-bold text-foreground mt-2">{stat.value}</p>
          </motion.div>
        ))}
      </div>

      {/* Recent Activity */}
      <div className="bg-card rounded-lg p-6 border border-border">
        <h2 className="text-xl font-semibold mb-4">Recent Activity</h2>
        <div className="space-y-4">
          {[1, 2, 3].map((item) => (
            <motion.div
              key={item}
              initial={{ x: -20, opacity: 0 }}
              animate={{ x: 0, opacity: 1 }}
              className="flex items-center gap-4 pb-4 border-b border-border last:border-0"
            >
              <div className="w-2 h-2 rounded-full bg-primary" />
              <div>
                <p className="font-medium">Task assigned to you</p>
                <p className="text-sm text-muted-foreground">2 hours ago</p>
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </motion.div>
  );
}

export default Dashboard;
